import{_ as e,o as r,c as t,a2 as l}from"./chunks/framework.DIMps2S2.js";const b=JSON.parse('{"title":"牛熊证","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"derivatives/cbbc.md","filePath":"zh-CN/derivatives/cbbc.md"}'),i={name:"derivatives/cbbc.md"};function o(h,a,n,d,s,c){return r(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="牛熊证" tabindex="-1">牛熊证 <a class="header-anchor" href="#牛熊证" aria-label="Permalink to &quot;牛熊证&quot;">​</a></h1><p>牛熊证定义、强制收回机制、R 类规则、结算示例及交易规则。</p><h2 id="什么是牛熊证" tabindex="-1">什么是牛熊证 <a class="header-anchor" href="#什么是牛熊证" aria-label="Permalink to &quot;什么是牛熊证&quot;">​</a></h2><p>牛熊证类属结构性产品，能追踪相关资产表现而无须支付购入实际资产的全部金额，具有杠杆效应。牛熊证设有固定到期日、行权价及回收价。</p><h3 id="牛证-bull" tabindex="-1">牛证（Bull） <a class="header-anchor" href="#牛证-bull" aria-label="Permalink to &quot;牛证（Bull）&quot;">​</a></h3><p>看涨工具。认为相关资产价格会上涨时买入，正股上涨则牛证价格相应上涨。</p><h3 id="熊证-bear" tabindex="-1">熊证（Bear） <a class="header-anchor" href="#熊证-bear" aria-label="Permalink to &quot;熊证（Bear）&quot;">​</a></h3><p>看跌工具。认为相关资产价格会下跌时买入，正股下跌则熊证价格相应上涨。</p><h2 id="强制收回机制-knock-out" tabindex="-1">强制收回机制（Knock-Out） <a class="header-anchor" href="#强制收回机制-knock-out" aria-label="Permalink to &quot;强制收回机制（Knock-Out）&quot;">​</a></h2><p>牛熊证独有的核心机制，也是最大的风险点。每只牛熊证都有一个收回价（Knock-Out Price）：</p><ul><li>牛证：正股价格下跌到或跌破收回价 → 强制收回，停止交易</li><li>熊证：正股价格上涨到或涨破收回价 → 强制收回，停止交易</li></ul><p>触发强制收回后，投资者将损失大部分甚至全部投资。</p><h3 id="r-类牛熊证" tabindex="-1">R 类牛熊证 <a class="header-anchor" href="#r-类牛熊证" aria-label="Permalink to &quot;R 类牛熊证&quot;">​</a></h3><p>R 类牛熊证的行权价 ≠ 回收价。触发收回后，根据强制回收时间至下一个交易时段结束的相关资产最低价（牛证）或最高价（熊证）计算结算价。如最低价/最高价触及或超越行使价，牛熊证可能没有任何剩余价值。</p><h3 id="计价时段规则" tabindex="-1">计价时段规则 <a class="header-anchor" href="#计价时段规则" aria-label="Permalink to &quot;计价时段规则&quot;">​</a></h3><ul><li>上午被回收：计价到当日下午交易时段结束</li><li>下午被回收：计价到下一个交易日中午时段结束</li></ul><h2 id="结算示例" tabindex="-1">结算示例 <a class="header-anchor" href="#结算示例" aria-label="Permalink to &quot;结算示例&quot;">​</a></h2><h3 id="牛证示例" tabindex="-1">牛证示例 <a class="header-anchor" href="#牛证示例" aria-label="Permalink to &quot;牛证示例&quot;">​</a></h3><p>行权价 125，回收价 128，换股比率 100：</p><p><strong>未触及回收价（正股结算价 132）</strong><br> 投资者可取回 =（132 - 125）÷ 100 = 0.07</p><p><strong>触及回收价（计价时段正股最低价 126）</strong><br> 投资者可取回 =（126 - 125）÷ 100 = 0.01</p><p>最坏情况：最低价等于或低于行权价，投资者无法取得任何剩余价值。</p><h3 id="熊证示例" tabindex="-1">熊证示例 <a class="header-anchor" href="#熊证示例" aria-label="Permalink to &quot;熊证示例&quot;">​</a></h3><p>行权价 135，回收价 130，换股比率 100：</p><p><strong>未触及回收价（正股结算价 128）</strong><br> 投资者可取回 =（135 - 128）÷ 100 = 0.07</p><p><strong>触及回收价（计价时段正股最高价 131）</strong><br> 投资者可取回 =（135 - 131）÷ 100 = 0.04</p><p>最坏情况：最高价等于或高于行权价，投资者无法取得任何剩余价值。</p><h3 id="结算价说明" tabindex="-1">结算价说明 <a class="header-anchor" href="#结算价说明" aria-label="Permalink to &quot;结算价说明&quot;">​</a></h3><ul><li>个股牛熊证：结算价为到期前一个交易日的正股收市价</li><li>指数牛熊证：结算水平为到期月份的期指结算水平</li></ul><h2 id="到期或回收后的处理" tabindex="-1">到期或回收后的处理 <a class="header-anchor" href="#到期或回收后的处理" aria-label="Permalink to &quot;到期或回收后的处理&quot;">​</a></h2><p>牛熊证到期或回收后无需额外操作。如有剩余价值，发行商结算后长桥会在一周内将剩余价值自动存入账户，对应牛熊证预计一周内从持仓中消失。建议留意日结单查看具体情况。</p><h2 id="交易规则" tabindex="-1">交易规则 <a class="header-anchor" href="#交易规则" aria-label="Permalink to &quot;交易规则&quot;">​</a></h2><h3 id="交易时段" tabindex="-1">交易时段 <a class="header-anchor" href="#交易时段" aria-label="Permalink to &quot;交易时段&quot;">​</a></h3><p>牛熊证在港股持续交易时段交易，与港股交易时间一致。</p><h3 id="交易入口" tabindex="-1">交易入口 <a class="header-anchor" href="#交易入口" aria-label="Permalink to &quot;交易入口&quot;">​</a></h3><p>股票详情页进入轮证页面，点击对应牛熊证，选择「买入」或「卖出」，输入价格和数量下单。</p><h3 id="支持订单类型" tabindex="-1">支持订单类型 <a class="header-anchor" href="#支持订单类型" aria-label="Permalink to &quot;支持订单类型&quot;">​</a></h3><p>限价单、市价单、条件单、策略单及长期单。</p><h3 id="最小交易单位" tabindex="-1">最小交易单位 <a class="header-anchor" href="#最小交易单位" aria-label="Permalink to &quot;最小交易单位&quot;">​</a></h3><p>按照牛熊证自身的手数限制。</p><h3 id="交收规则" tabindex="-1">交收规则 <a class="header-anchor" href="#交收规则" aria-label="Permalink to &quot;交收规则&quot;">​</a></h3><p>T+0 交易，T+2 交收，均为现金结算。</p><h2 id="简称含义" tabindex="-1">简称含义 <a class="header-anchor" href="#简称含义" aria-label="Permalink to &quot;简称含义&quot;">​</a></h2><p>格式：股票名 + 发行机构 + 月份 + 牛/熊 + 系列编号</p><p>月份表示：1-10 月用中文数字，11 月为「甲」，12 月为「乙」。</p><h2 id="剩余价值查询" tabindex="-1">剩余价值查询 <a class="header-anchor" href="#剩余价值查询" aria-label="Permalink to &quot;剩余价值查询&quot;">​</a></h2><p><a href="https://hk.warrants.com/tc/cbbc/residual-value" target="_blank" rel="noreferrer">牛熊证回收和剩余价值查询</a></p><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/derivatives">衍生品</a></li></ul>',49)])])}const p=e(i,[["render",o]]);export{b as __pageData,p as default};
